import { readFile } from "node:fs/promises";

import { defineEval } from "niceeval";
import { commandSucceeded } from "niceeval/expect";

const fixture = (path: string) => new URL(`../fixtures/yet-another-react-lightbox/pr-417/${path}`, import.meta.url);

// real fix: yet-another-react-lightbox PR #417 (squash-merged as
// 18dc3afe76de67c4f6ea576ab9289b98bf36c550), which lands on top of BASE_COMMIT (its first
// parent, verified equal to `gh pr view --json baseRefOid`). Bug: the download plugin's
// cross-origin XHR download path never inspected the response's Content-Disposition header,
// so the server-provided filename (including the RFC 5987 filename* form) was discarded and
// the file was saved under a generic blob-derived name whenever no explicit filename was
// configured.
const REPO_URL = "https://github.com/igordanchenko/yet-another-react-lightbox.git";
const BASE_COMMIT = "c61a2458db31202faf4681f444362acdb21721ec";

export default defineEval({
  description:
    "yet-another-react-lightbox pr-417: use the server-provided Content-Disposition filename for cross-origin " +
    "downloads instead of discarding it (real yet-another-react-lightbox issue)",
  // 纯 npm 仓库,无 packageManager 字段(不用 corepack);package-lock.json 提交在根目录。
  // 本地实测 npm install 数秒,vitest 跑单文件 <2s。这个 base commit(2026-07)的 package.json
  // 已经把 vitest/vite/jsdom 升到 4.1.x/8.x/29.x,这条链在依赖里隐式要求 Node 同步
  // require(esm)(Node 20.19.0/22.12.0 才 stable);E2B 沙箱固定 Node v20.9.0,装完直接在
  // vite 的 rolldown 依赖(缺 util.styleText)和 jsdom 的 html-encoding-sniffer→@exodus/bytes
  // 链上各挂一次。本地在 fnm 20.9.0 下实测复现,并验证 vitest@3.2.7/jsdom@26.1.0 组合可在同一
  // Node 版本跑通 RED→GREEN。这几个版本号在装依赖前直接写进 package.json(而不是装完后用
  // --no-save 叠一层),让 npm install 变成幂等的——本地实测过 agent 中途再跑一次 npm
  // install/npm ci 幂等保持 3.2.7 不回弹到 4.1.10(用 --no-save 叠加验证过一次,agent 重装会让
  // vitest 弹回 4.1.10 并在 20.9.0 上崩掉,已改为下面这种写回 package.json 的写法)。
  // package.json/package-lock.json 因此会被这一步合法改写,一并排除出 diff。沿用全局默认
  // timeoutMs。
  diff: {
    ignore: ["coverage", "node_modules", "package.json", "package-lock.json"],
  },
  async test(t) {
    // 没有单独的 workspace 起始目录——fixture 就是这个 base commit 本身:clone 真实 repo、
    // 退到 base commit、抹掉未来历史(remote/tags/reflog),agent 拿到带真实(截断)git 历史
    // 的 checkout。checkout 必须在 workdir 根——嵌套子目录会被 diff 分类账记成 gitlink,
    // agent 的改动就从证据里消失了。任务说明只通过下面的 t.send() 传给 agent。
    t.progress({ message: "cloning yet-another-react-lightbox @ base commit" });
    const cloned = await t.sandbox.runShell(
      [
        "set -euo pipefail",
        `git clone -q -o origin --single-branch ${REPO_URL} .yarl-clone`,
        "mv .yarl-clone/.git .git",
        "rm -rf .yarl-clone",
        `git reset -q --hard ${BASE_COMMIT}`,
        "git remote remove origin",
        "git tag -l | xargs -r git tag -d >/dev/null",
        "git reflog expire --expire=now --all",
        "git gc -q --prune=now",
        // 上游同款自检:base commit 之后不应再有任何 commit 可见
        `TS=$(git show -s --format=%ci ${BASE_COMMIT})`,
        'COUNT=$(git log --oneline --since="$TS" | wc -l)',
        '[ "$COUNT" -eq 1 ]',
      ].join("\n"),
    );
    if (cloned.exitCode !== 0) {
      throw new Error(
        `yet-another-react-lightbox checkout failed: ${(cloned.stderr || cloned.stdout).trim().slice(-500)}`,
      );
    }

    t.progress({ message: "pinning Node-20.9.0-compatible test toolchain" });
    // 见上方 diff.ignore 注释:base commit 的 package.json 把 vitest/@vitest/coverage-v8/
    // @vitest/ui/jsdom 都固定在依赖 Node 同步 require(esm) 的版本上,在这个沙箱的
    // Node v20.9.0 上装完就跑不动。直接改写 package.json 里这四行声明版本,再走一次
    // 正常 npm install 生成匹配的 lockfile——这样不管 agent 后面重跑多少次 npm install /
    // npm ci,都会稳定收敛回这组能在 20.9.0 上跑的版本,不会像装完后再叠一层
    // --no-save 覆盖那样被下一次 install 冲掉。
    const pinned = await t.sandbox.runShell(
      [
        "set -euo pipefail",
        String.raw`sed -i.bak -e 's/"@vitest\/coverage-v8": "\^4.1.3"/"@vitest\/coverage-v8": "3.2.7"/' -e 's/"@vitest\/ui": "\^4.1.3"/"@vitest\/ui": "3.2.7"/' -e 's/"jsdom": "\^29.1.1"/"jsdom": "26.1.0"/' -e 's/"vitest": "\^4.1.3"/"vitest": "3.2.7"/' package.json`,
        "rm -f package.json.bak",
        // 自检:四处替换都必须命中,否则说明上游改了版本号,不能悄悄装出一个没验证过的组合
        `grep -q '"@vitest/coverage-v8": "3.2.7"' package.json`,
        `grep -q '"@vitest/ui": "3.2.7"' package.json`,
        `grep -q '"jsdom": "26.1.0"' package.json`,
        `grep -q '"vitest": "3.2.7"' package.json`,
      ].join("\n"),
    );
    if (pinned.exitCode !== 0) {
      throw new Error(`toolchain pin failed: ${(pinned.stderr || pinned.stdout).trim().slice(-500)}`);
    }

    t.progress({ message: "npm install" });
    const installed = await t.sandbox.runShell("npm install");
    if (installed.exitCode !== 0) {
      throw new Error(`npm install failed: ${(installed.stderr || installed.stdout).trim().slice(-500)}`);
    }

    await t
      .send(
        "Your working directory is a checkout of the real yet-another-react-lightbox repository at the commit " +
          "where the bug below reproduces. Find and fix the bug in the library source.\n\n" +
          "Bug: this library renders a photo/video lightbox with an optional download plugin that lets the user " +
          "save the currently displayed image. When the image lives on a different origin than the page, the " +
          "plugin can't just point a plain anchor tag at it (cross-origin downloads via a plain `<a download>` " +
          "don't reliably work), so it fetches the image itself over XHR and then hands the resulting Blob, " +
          "together with an optional caller-supplied filename, to a small local `saveAs` helper that triggers " +
          "the actual save. If the caller didn't configure an explicit filename for the slide/download, the " +
          "saved file should still get a meaningful name: the HTTP response for the image may include a " +
          "`Content-Disposition` header naming the file server-side (e.g. `attachment; filename=\"photo.jpg\"`, " +
          "or the RFC 5987 extended form `filename*=UTF-8''caf%C3%A9.jpg` for non-ASCII names), and that name " +
          "should be used as a fallback. Right now, nothing in the cross-origin download path ever looks at " +
          "this response header at all, so whenever no explicit filename is configured, the file always saves " +
          "under a generic name the browser derives from the blob URL instead of the name the server intended.\n\n" +
          "Expected behavior once fixed, spelled out precisely since it's pure header-parsing logic:\n" +
          "- A missing/null header, an empty header, or a header with no `filename`/`filename*` parameter at " +
          "all (e.g. just `inline`) means there's no server-provided name to fall back to.\n" +
          "- A plain `filename` parameter may be unquoted (`filename=photo.jpg`) or double-quoted " +
          '(`filename="photo.jpg"`); use the value as-is with surrounding whitespace trimmed and surrounding ' +
          "quotes stripped. Extra whitespace around the `=` or after the value before the next `;` (e.g. " +
          "`filename = photo.jpg ; size=1024`) should not break parsing.\n" +
          '- An empty quoted value (`filename=""`) counts as no filename.\n' +
          "- Per RFC 5987/6266, when both an extended `filename*=UTF-8''<percent-encoded>` parameter and a " +
          "plain `filename` parameter are present, the extended (percent-decoded) one takes precedence, e.g. " +
          "`filename*=UTF-8''na%C3%AFve.jpg` should decode to `naïve.jpg`.\n" +
          "- If the `filename*` value has malformed percent-encoding, or decodes to an empty/whitespace-only " +
          "string, parsing must not throw -- it should fall back to the plain `filename` parameter instead, if " +
          "one is present.\n\n" +
          "Environment notes: dependencies are already installed (Node, npm). You can scope the existing Vitest " +
          "suite to whatever file you're iterating on with `npx vitest run <path-to-file>`. Fix the library " +
          "source; do not just add workarounds in test files.",
      )
      .then((turn) => turn.expectOk());

    const downloadTest = await readFile(fixture("tests/Download.spec.ts"), "utf8");
    const runTests = await readFile(fixture("tests/run-tests.sh"), "utf8");
    await t.sandbox.writeFiles({
      "test/unit/plugins/Download.spec.ts": downloadTest,
      "tests/run-tests.sh": runTests,
    });

    t.check(await t.sandbox.runCommand("bash", ["tests/run-tests.sh"]), commandSucceeded());
  },
});
